import test from "node:test";
import assert from "node:assert/strict";

import { catalogCacheKey } from "../src/catalog-cache-key.mjs";
import { AsyncSlotCache } from "../src/async-slot-cache.mjs";
import { CatalogService } from "../src/catalog-service.mjs";

test("preference lists with different priority produce distinct cache identities", () => {
  const frenchFirst = catalogCacheKey({ tenant: "acme", preferredLocales: ["fr", "en"] });
  const englishFirst = catalogCacheKey({ tenant: "acme", preferredLocales: ["en", "fr"] });
  assert.notEqual(frenchFirst, englishFirst);
});

test("reversing locale preference selects the newly preferred available catalog", async () => {
  let loads = 0;
  const service = new CatalogService({
    cache: new AsyncSlotCache(),
    availableLocales: ["en", "fr"],
    async loadCatalog({ tenant, locale }) {
      loads += 1;
      return { tenant, locale, load: loads };
    }
  });

  const french = await service.getCatalog({ tenant: "acme", preferredLocales: ["fr", "en"] });
  const english = await service.getCatalog({ tenant: "acme", preferredLocales: ["en", "fr"] });
  assert.equal(french.locale, "fr");
  assert.equal(english.locale, "en");
  assert.equal(loads, 2);
});
